// Initialiser le polling
const conversation = $input.first().json.conversation;

return [{
  json: {
    conversationId: conversation.sId,
    attempt: 0,
    maxAttempts: 60,
    isComplete: false
  }
}];

const response = $input.first().json;
const prevData = $('Wait 10s').first().json;
const conversation = response.conversation || response;
let isComplete = false;
let agentContent = null;
let agentStatus = 'unknown';

// Parcourir les messages pour trouver l'agent
if (conversation.content && Array.isArray(conversation.content)) {
  for (const messageGroup of conversation.content) {
    for (const message of messageGroup) {
      if (message.type === 'agent_message') {
        agentStatus = message.status || 'unknown';
        agentContent = message.content || null;

        // L'agent a terminé si:
        // 1. Status = 'succeeded' ou 'failed' ou 'cancelled'
        // 2. OU le contenu contient un bloc JSON fermé
        const terminalStatuses = ['succeeded', 'failed', 'cancelled'];
        const hasTerminalStatus = terminalStatuses.includes(message.status);
        const hasCompleteJson = typeof message.content === 'string' && 
                                message.content.includes('```json') && 
                                message.content.includes('```\n') &&
                                message.content.split('```').length >= 3;

        isComplete = hasTerminalStatus || hasCompleteJson;
      }
    }
  }
}

const newAttempt = (prevData.attempt || 0) + 1;

// Timeout après 60 tentatives (3 min)
if (newAttempt >= 60 && !isComplete) {
  throw new Error(`Timeout après ${newAttempt} tentatives. Dernier status: ${agentStatus}`);
}

return [{
  json: {
    conversationId: prevData.conversationId,
    attempt: newAttempt,
    maxAttempts: 60,
    isComplete: Boolean(isComplete),
    agentStatus: String(agentStatus),
    agentContent: agentContent || "",
    contentLength: agentContent?.length || 0,
    conversation: conversation
  }
}];

// Extraire le contenu final de l'agent
const data = $input.first().json;
const content = data.agentContent || '';

// Extraire le JSON du bloc markdown
let extractedJson = null;
const jsonMatch = content.match(/```json\n([\s\S]*?)\n```/);

if (jsonMatch && jsonMatch[1]) {
  try {
    extractedJson = JSON.parse(jsonMatch[1]);
  } catch (e) {
    console.log('Failed to parse JSON:', e.message);
  }
}

return [{
  json: {
    conversationId: data.conversationId,
    attempts: data.attempt,
    status: data.agentStatus,
    rawContent: content,
    parsedData: extractedJson,
    conversationUrl: `https://dust.tt/w/7475ab5b7b/assistant/${data.conversationId}`
  }
}];

// ============================================
// Premier Filtre — Adapté pour payload Unipile (via Start)
// Analyse le contenu email (liens DocSend/Drive/Tally/Deck)
// et détermine le routage
// ============================================

const items = $input.all();
const results = [];

for (const item of items) {
  const email = item.json || item;

  // === PDF : déjà géré par le nœud "Start" ===
  const hasPdf = email.hasPdf === true;
  const hasLargePdf = hasPdf && (email.size || 0) > 10 * 1024;

  // === CONTENU EMAIL ===
  const textContent = email.text || email.snippet || '';
  const htmlContent = email.html || '';
  const fullContent = textContent + ' ' + htmlContent;

  // === FONCTION UTILITAIRE: Décoder les entités HTML ===
  function decodeHtmlEntities(str) {
    if (!str) return str;
    return str
      .replace(/&amp;/g, '&')
      .replace(/&lt;/g, '<')
      .replace(/&gt;/g, '>')
      .replace(/&quot;/g, '"')
      .replace(/&#39;/g, "'");
  }

  function parseUrlParams(url) {
    const params = {};
    const queryIndex = url.indexOf('?');
    if (queryIndex === -1) return params;
    const queryString = url.substring(queryIndex + 1);
    const pairs = queryString.split('&');
    for (const pair of pairs) {
      const eqIndex = pair.indexOf('=');
      if (eqIndex !== -1) {
        const key = pair.substring(0, eqIndex);
        const value = pair.substring(eqIndex + 1);
        params[key] = decodeURIComponent(value);
      }
    }
    return params;
  }

  function getPathname(url) {
    const match = url.match(/https?:\/\/[^\/]+(\/[^?]*)/);
    return match ? match[1] : '';
  }

  // === DÉTECTION LIENS TALLY STORAGE ===
  function extractTallyLinks(content) {
    const tallyLinks = [];
    const hrefTallyRegex = /href=["']([^"']*storage\.tally\.so[^"']*)["']/gi;
    let matchTally;
    while ((matchTally = hrefTallyRegex.exec(content)) !== null) {
      const originalUrl = matchTally[1];
      const decodedUrl = decodeHtmlEntities(originalUrl);
      const params = parseUrlParams(decodedUrl);
      const pathname = getPathname(decodedUrl);
      const pathParts = pathname.split('/');
      const fileName = pathParts[pathParts.length - 1] || '';
      const tallyParams = {
        url: decodedUrl, originalUrl, id: params.id || null,
        accessToken: params.accessToken || null, signature: params.signature || null,
        fileName, fileNameClean: decodeURIComponent(fileName).replace(/-/g, ' ').replace('.pdf', ''),
        isPrivate: pathname.includes('/private/'), isPdf: fileName.toLowerCase().endsWith('.pdf'),
        confidence: 'high', type: 'tally_storage'
      };
      tallyParams.isValid = !!(tallyParams.id && tallyParams.accessToken && tallyParams.signature);
      if (tallyParams.isValid && !tallyLinks.some(l => l.id === tallyParams.id)) {
        tallyLinks.push(tallyParams);
      }
    }
    return tallyLinks;
  }

  const tallyLinks = extractTallyLinks(fullContent);
  const hasTally = tallyLinks.length > 0;
  const primaryTally = tallyLinks[0] || null;

  // === DÉTECTION LIENS DOCSEND ===
  function extractDocSendLinks(content) {
    const links = [];
    const directPatterns = [
      /https?:\/\/(www\.)?docsend\.com\/(view|v)\/[a-zA-Z0-9_-]+/gi,
      /https?:\/\/(www\.)?docsend\.com\/d\/[a-zA-Z0-9_-]+/gi,
      /https?:\/\/[a-zA-Z0-9-]+\.docsend\.com\/view\/[a-zA-Z0-9_-]+/gi
    ];
    for (const regex of directPatterns) {
      const matches = content.match(regex) || [];
      links.push(...matches.map(url => ({ url, type: 'direct', confidence: 'high' })));
    }
    const hrefDocsendRegex = /href=["']([^"']*docsend[^"']*)["']/gi;
    let matchDoc;
    while ((matchDoc = hrefDocsendRegex.exec(content)) !== null) {
      const url = matchDoc[1];
      if (!links.some(l => l.url === url)) {
        links.push({ url, type: 'href_contains_docsend', confidence: 'high' });
      }
    }
    const trackingRegex = /<a[^>]*href=["']([^"']+)["'][^>]*>([^<]*(?:deck|docsend|pitch|présentation|presentation)[^<]*)<\/a>/gi;
    let matchTracking;
    while ((matchTracking = trackingRegex.exec(content)) !== null) {
      const url = matchTracking[1];
      const anchorText = matchTracking[2];
      if (!url.includes('drive.google.com') && !url.includes('docs.google.com') &&
          !url.includes('storage.tally.so') && !links.some(l => l.url === url)) {
        links.push({ url, type: 'tracking_with_deck_context', anchorText: anchorText.trim(), confidence: 'medium' });
      }
    }
    const visibleDocsendRegex = />([^<]*docsend[^<]*)</gi;
    return { links, hasVisibleMention: visibleDocsendRegex.test(content) };
  }

  const docSendAnalysis = extractDocSendLinks(fullContent);
  const uniqueDocSendLinks = [...new Map(docSendAnalysis.links.map(l => [l.url, l])).values()];
  const highConfidenceDocSend = uniqueDocSendLinks.filter(l => l.confidence === 'high');
  const mediumConfidenceDocSend = uniqueDocSendLinks.filter(l => l.confidence === 'medium');
  const hasDocSend = uniqueDocSendLinks.length > 0;
  const hasConfirmedDocSend = highConfidenceDocSend.length > 0;
  const primaryDocSend = highConfidenceDocSend[0] || mediumConfidenceDocSend[0] || null;

  // === DÉTECTION LIENS DECK (tracking URLs) ===
  function extractDeckLinks(htmlContentParam) {
    const deckLinks = [];
    const deckAnchorRegex = /<a[^>]*href=["']([^"']+)["'][^>]*>([\s\S]*?)<\/a>/gi;
    let matchDeck;
    while ((matchDeck = deckAnchorRegex.exec(htmlContentParam)) !== null) {
      const url = matchDeck[1];
      const anchorContent = matchDeck[2];
      const anchorText = anchorContent.replace(/<[^>]+>/g, ' ').replace(/&[^;]+;/g, ' ').replace(/\s+/g, ' ').trim().toLowerCase();
      const deckKeywords = ['le deck', 'the deck', 'our deck', 'pitch deck', 'investor deck',
        'deck ici', 'deck here', 'voir le deck', 'view deck', 'access deck',
        'télécharger le deck', 'download deck', 'lien deck', 'deck link', 'présentation', 'presentation'];
      const isDeckLink = deckKeywords.some(kw => anchorText.includes(kw)) ||
                         (anchorText.includes('deck') && anchorText.length < 50);
      if (isDeckLink && !url.includes('drive.google.com') && !url.includes('docs.google.com') &&
          !url.includes('docsend.com') && !url.includes('storage.tally.so') &&
          !url.includes('désinscrire') && !url.includes('unsubscribe')) {
        let confidence = 'medium';
        if (anchorText.includes('le deck') || anchorText.includes('pitch deck') || anchorText.includes('the deck')) confidence = 'high';
        deckLinks.push({ url, anchorText: anchorContent.replace(/<[^>]+>/g, '').trim(), type: 'tracking_deck_link', confidence });
      }
    }
    const unique = [...new Map(deckLinks.map(l => [l.url, l])).values()];
    unique.sort((a, b) => (a.confidence === 'high' ? -1 : 1) - (b.confidence === 'high' ? -1 : 1));
    return unique;
  }

  const deckLinks = extractDeckLinks(htmlContent);
  const hasDeckLink = deckLinks.length > 0;
  const primaryDeckLink = deckLinks[0] || null;
  const highConfidenceDeckLinks = deckLinks.filter(l => l.confidence === 'high');

  // === DÉTECTION LIENS GOOGLE DRIVE ===
  function getContext(content, url, windowSize = 100) {
    const index = content.toLowerCase().indexOf(url.toLowerCase());
    if (index === -1) return '';
    return content.substring(Math.max(0, index - windowSize), Math.min(content.length, index + url.length + windowSize)).toLowerCase();
  }

  function scoreDriveLink(context, url) {
    let score = 0;
    const deckKw = ['pitch deck', 'pitch-deck', 'pitchdeck', 'deck', 'présentation', 'presentation',
      'investor deck', 'fundraising deck', 'le deck', 'the deck', 'our deck', 'ci-joint', 'attached', 'voici le', 'slide', 'slides'];
    const annexKw = ['executive summary', 'exec summary', 'summary', 'one-pager', 'one pager', 'onepager',
      'annexe', 'annex', 'appendix', 'financials', 'projections', 'forecast', 'data room', 'dataroom', 'teaser', 'memo', 'note'];
    for (const kw of deckKw) { if (context.includes(kw)) score += 10; }
    for (const kw of annexKw) { if (context.includes(kw)) score -= 5; }
    const urlLower = url.toLowerCase();
    if (urlLower.includes('deck') || urlLower.includes('pitch')) score += 5;
    if (urlLower.includes('summary') || urlLower.includes('annex')) score -= 3;
    return score;
  }

  let googleDriveFiles = [];
  let matchDrive;
  const driveFileRegex = /https?:\/\/drive\.google\.com\/file\/d\/([a-zA-Z0-9_-]+)[^\s<")']*/gi;
  while ((matchDrive = driveFileRegex.exec(fullContent)) !== null) {
    const url = matchDrive[0].split(/[<")'>\s]/)[0];
    const context = getContext(fullContent, url);
    googleDriveFiles.push({ url, fileId: matchDrive[1], type: 'file', context, score: scoreDriveLink(context, url), position: matchDrive.index });
  }
  const driveOpenRegex = /https?:\/\/drive\.google\.com\/open\?id=([a-zA-Z0-9_-]+)/gi;
  while ((matchDrive = driveOpenRegex.exec(fullContent)) !== null) {
    const url = matchDrive[0];
    const context = getContext(fullContent, url);
    googleDriveFiles.push({ url, fileId: matchDrive[1], type: 'file', context, score: scoreDriveLink(context, url), position: matchDrive.index });
  }
  const docsRegex = /https?:\/\/docs\.google\.com\/(document|presentation|spreadsheets|drawings)\/d\/([a-zA-Z0-9_-]+)[^\s<")']*/gi;
  while ((matchDrive = docsRegex.exec(fullContent)) !== null) {
    const url = matchDrive[0].split(/[<")'>\s]/)[0];
    const docType = matchDrive[1];
    const context = getContext(fullContent, url);
    let score = scoreDriveLink(context, url);
    if (docType === 'presentation') score += 8;
    if (docType === 'spreadsheets') score -= 3;
    googleDriveFiles.push({ url, fileId: matchDrive[2], type: docType, context, score, position: matchDrive.index });
  }
  const seenIds = new Set();
  googleDriveFiles = googleDriveFiles.filter(f => { if (seenIds.has(f.fileId)) return false; seenIds.add(f.fileId); return true; });
  googleDriveFiles.sort((a, b) => a.position - b.position);
  if (googleDriveFiles.length > 0) googleDriveFiles[0].score += 3;
  const sortedByScore = [...googleDriveFiles].sort((a, b) => b.score - a.score);
  const hasGoogleDrive = googleDriveFiles.length > 0;
  const primaryDeck = sortedByScore[0] || null;
  const annexFiles = sortedByScore.slice(1);

  // === ROUTAGE ===
  let routeType = 'text_only';
  if (hasLargePdf)       routeType = 'pdf_attachment';
  else if (hasTally)     routeType = 'tally';
  else if (hasGoogleDrive) routeType = 'google_drive';
  else if (hasDocSend)   routeType = 'docsend';
  else if (hasDeckLink)  routeType = 'deck_link';

  // === OUTPUT ===
  const output = {
    json: {
      // Identité email (passthrough depuis Start)
      messageId: email.id || '',
      subject: email.subject || '',
      from: email.from || '',
      to: email.to || '',
      date: email.date || '',
      // PDF (depuis Start)
      hasAttachments: email.hasAttachments || false,
      hasLargeAttachment: hasLargePdf,
      hasPdf: hasPdf,
      hasLargePdf: hasLargePdf,
      largestPdfFilename: hasPdf ? email.filename : null,
      largestPdfSizeKB: hasPdf ? Math.round((email.size || 0) / 1024) : null,
      // DocSend
      hasDocSend, hasConfirmedDocSend,
      docSendUrl: primaryDocSend?.url || null,
      docSendType: primaryDocSend?.type || null,
      docSendConfidence: primaryDocSend?.confidence || null,
      docSendAnchorText: primaryDocSend?.anchorText || null,
      allDocSendLinks: uniqueDocSendLinks,
      highConfidenceDocSend, mediumConfidenceDocSend,
      docSendCount: uniqueDocSendLinks.length,
      hasVisibleDocsendMention: docSendAnalysis.hasVisibleMention,
      docSendApiPayload: hasDocSend ? { url: primaryDocSend.url } : null,
      // Deck links
      hasDeckLink,
      deckLinkUrl: primaryDeckLink?.url || null,
      deckLinkAnchorText: primaryDeckLink?.anchorText || null,
      deckLinkConfidence: primaryDeckLink?.confidence || null,
      allDeckLinks: deckLinks, highConfidenceDeckLinks,
      deckLinkCount: deckLinks.length,
      // Tally
      hasTally,
      tallyUrl: primaryTally?.url || null,
      tallyId: primaryTally?.id || null,
      tallyAccessToken: primaryTally?.accessToken || null,
      tallySignature: primaryTally?.signature || null,
      tallyFileName: primaryTally?.fileName || null,
      tallyFileNameClean: primaryTally?.fileNameClean || null,
      tallyIsValid: primaryTally?.isValid || false,
      allTallyLinks: tallyLinks, tallyCount: tallyLinks.length,
      // Google Drive
      hasGoogleDrive,
      hasMultipleGoogleDrive: googleDriveFiles.length > 1,
      googleDriveCount: googleDriveFiles.length,
      primaryDeck, primaryDeckFileId: primaryDeck?.fileId || null,
      primaryDeckUrl: primaryDeck?.url || null, primaryDeckScore: primaryDeck?.score || null,
      annexFiles, annexFileIds: annexFiles.map(f => f.fileId),
      allGoogleDriveFiles: sortedByScore,
      // Routage
      routeType,
      routeToPdfOCR: routeType === 'pdf_attachment',
      routeToTally: routeType === 'tally',
      routeToGoogleDrive: routeType === 'google_drive',
      routeToDocSend: routeType === 'docsend',
      routeToDeckLink: routeType === 'deck_link',
      routeToTextOnly: routeType === 'text_only'
    }
  };

  // Passer le binary PDF s'il existe (vient du nœud Start)
  if (hasLargePdf && item.binary && item.binary.data) {
    output.binary = { data: item.binary.data };
  }

  results.push(output);
}

return results;

const html = $input.first().json.data;
const inputUrl = $('premier filtre').item.json.deckLinkUrl || '';

let finalUrl = null;
let fileId = null;
let sourceType = 'other';

// Pattern 1: meta http-equiv="refresh"
const metaMatch = html.match(/content="[^;]*;([^"]+)"/);
if (metaMatch) {
  finalUrl = metaMatch[1];
}

// Pattern 2: top.location dans le JS
if (!finalUrl) {
  const jsMatch = html.match(/top\.location='([^']+)'/);
  if (jsMatch) {
    finalUrl = jsMatch[1].replace(/\\\//g, '/');
  }
}

// Pattern 3: lien docsend dans le HTML brut
if (!finalUrl) {
  const docsendMatch = html.match(/https:\/\/docsend\.com\/view\/[a-zA-Z0-9]+/);
  if (docsendMatch) {
    finalUrl = docsendMatch[0];
  }
}

// Détection du type de source (sur finalUrl OU inputUrl)
const urlToCheck = finalUrl || inputUrl;

if (urlToCheck) {
  if (urlToCheck.includes('docsend.com')) {
    sourceType = 'docsend';
  } else if (urlToCheck.includes('drive.google.com') || urlToCheck.includes('docs.google.com')) {
    sourceType = 'google_drive';
    const idMatch = urlToCheck.match(/\/d\/([a-zA-Z0-9_-]+)/);
    fileId = idMatch ? idMatch[1] : null;
  } else if (urlToCheck.includes('dropbox.com')) {
    sourceType = 'dropbox';
  } else if (urlToCheck.includes('onedrive.live.com') || urlToCheck.includes('sharepoint.com')) {
    sourceType = 'onedrive';
  } else if (urlToCheck.includes('notion.so') || urlToCheck.includes('notion.site')) {
    sourceType = 'notion';
  } else if (urlToCheck.includes('box.com')) {
    sourceType = 'box';
  } else if (/\.(pdf|pptx?|docx?|xlsx?)(\?|$)/i.test(urlToCheck)) {
    sourceType = 'direct_file';
  }
}

return {
  finalUrl: finalUrl,
  inputUrl: inputUrl,
  googleDriveFileId: fileId,
  sourceType: sourceType,
  isDocsend: sourceType === 'docsend',
  isGoogleDrive: sourceType === 'google_drive',
  requiresSpecialHandling: ['docsend', 'notion', 'box'].includes(sourceType)
};

// Récupérer les données binaires depuis N8N
const binaryData = items[0].binary || {};

// Convertir les clés binaires en array avec infos
const files = Object.entries(binaryData).map(([key, data]) => ({
  key: key,
  fileName: data.fileName || key,
  mimeType: data.mimeType || '',
  size: data.data ? Buffer.from(data.data, 'base64').length : 0,
  data: data
}));

console.log('All files:', files.map(f => ({ 
  name: f.fileName, 
  type: f.mimeType, 
  size: `${(f.size / 1024 / 1024).toFixed(2)}MB` 
})));

// Filtrer : uniquement les PDFs
const pdfs = files.filter(f => {
  const isPDF = f.mimeType === 'application/pdf' || 
                f.fileName.toLowerCase().endsWith('.pdf');
  return isPDF;
});

console.log(`PDFs found: ${pdfs.length}`);

if (pdfs.length === 0) {
  // Aucun PDF trouvé
  return [{
    json: {
      hasPDF: false,
      message: "Aucun PDF détecté",
      filesFound: files.map(f => ({ 
        name: f.fileName, 
        type: f.mimeType, 
        size: f.size 
      }))
    }
  }];
}

// Trouver le PDF le plus lourd
const largestPDF = pdfs.reduce((max, current) => {
  return current.size > max.size ? current : max;
});

console.log(`Selected PDF: ${largestPDF.fileName} (${(largestPDF.size / 1024 / 1024).toFixed(2)}MB)`);

// Retourner UNIQUEMENT le PDF sélectionné en binary
const result = [{
  json: {
    hasPDF: true,
    selectedFile: largestPDF.fileName,
    sizeMB: (largestPDF.size / 1024 / 1024).toFixed(2),
    mimeType: largestPDF.mimeType,
    message: `PDF sélectionné: ${largestPDF.fileName}`
  },
  binary: {
    // ✅ IMPORTANT : Passer UNIQUEMENT le PDF sous la clé "data"
    data: {
      data: largestPDF.data.data,
      mimeType: largestPDF.data.mimeType,
      fileName: largestPDF.data.fileName
    }
  }
}];

return result;

// ============================================================
// 🔧 BINARY FORCER - Récupère le binary depuis "premier filtre"
// ============================================================
// Ce nœud force la récupération du fichier binaire en allant
// chercher directement dans les données du nœud source.
// ============================================================

// Récupérer l'item courant
const currentItem = $input.first();

// 📌 MÉTHODE 1: Vérifier si le binary est déjà présent dans l'item courant
if (currentItem.binary && Object.keys(currentItem.binary).length > 0) {
  const binaryKeys = Object.keys(currentItem.binary);
  console.log('✅ Binary déjà présent dans l\'item courant');
  console.log('   Clés disponibles:', binaryKeys);

  // Standardiser sous "data" pour Mistral
  const firstKey = binaryKeys[0];
  return [{
    json: {
      ...currentItem.json,
      _binarySource: 'current_item',
      _binaryKey: firstKey
    },
    binary: {
      data: currentItem.binary[firstKey]
    }
  }];
}

// 📌 MÉTHODE 2: Aller chercher dans le nœud "premier filtre" via référence directe
try {
  // Accéder aux données du nœud "premier filtre"
  const premierFiltreData = $('premier filtre').first();

  console.log('🔍 Analyse du nœud "premier filtre"...');
  console.log('   JSON keys:', Object.keys(premierFiltreData.json || {}));
  console.log('   Has binary:', !!premierFiltreData.binary);

  // Vérifier si ce nœud a un binary
  if (premierFiltreData.binary && Object.keys(premierFiltreData.binary).length > 0) {
    const binaryKeys = Object.keys(premierFiltreData.binary);
    console.log('✅ Binary trouvé dans "premier filtre"');
    console.log('   Clés:', binaryKeys);

    const firstKey = binaryKeys[0];
    return [{
      json: {
        ...currentItem.json,
        _binarySource: 'premier_filtre_binary',
        _binaryKey: firstKey
      },
      binary: {
        data: premierFiltreData.binary[firstKey]
      }
    }];
  }

  // 📌 MÉTHODE 3: Le binary n'a pas été passé, mais on peut le reconstruire
  // depuis les infos stockées dans le JSON de "premier filtre"
  const jsonData = premierFiltreData.json;

  if (jsonData.largestPdf && jsonData.largestPdfKey) {
    console.log('⚠️ Binary non passé mais infos PDF disponibles');
    console.log('   PDF Key:', jsonData.largestPdfKey);
    console.log('   PDF Filename:', jsonData.largestPdfFilename);

    // On doit remonter au nœud source du binary (Gmail Trigger)
    // Essayons de trouver le trigger Gmail
    const possibleTriggerNames = [
      'Gmail Trigger',
      'Gmail Trigger1', 
      'Gmail',
      'Trigger',
      'Email Trigger',
      'When email received'
    ];

    for (const triggerName of possibleTriggerNames) {
      try {
        const triggerData = $(triggerName).first();
        if (triggerData.binary) {
          const targetKey = jsonData.largestPdfKey;
          if (triggerData.binary[targetKey]) {
            console.log(`✅ Binary récupéré depuis "${triggerName}"`);
            return [{
              json: {
                ...currentItem.json,
                _binarySource: triggerName,
                _binaryKey: targetKey
              },
              binary: {
                data: triggerData.binary[targetKey]
              }
            }];
          }

          // Si la clé exacte n'existe pas, prendre le premier binary disponible
          const availableKeys = Object.keys(triggerData.binary);
          if (availableKeys.length > 0) {
            console.log(`✅ Binary alternatif trouvé dans "${triggerName}"`);
            console.log('   Clés disponibles:', availableKeys);
            return [{
              json: {
                ...currentItem.json,
                _binarySource: triggerName,
                _binaryKey: availableKeys[0]
