function cleanEmailText(text) {
  if (!text) return '';
  return text
    .replace(/^>+\s?/gm, '')
    .replace(/\[image:[^\]]*\]/g, '')
    .replace(/\n-- \n[\s\S]*$/m, '')
    .replace(/^Le .+ a \u00e9crit\s?:\s*$/gm, '')
    .replace(/https?:\/\/app\.signitic\.com\/[^\s]*/g, '')
    .replace(/\n{3,}/g, '\n\n')
    .trim();
}

function cleanEmailHtml(html) {
  if (!html) return '';
  return html
    .replace(/<div[^>]*class="gmail_signature"[^>]*>[\s\S]*?<\/div>/gi, '')
    .replace(/<div[^>]*class="gmail_attr"[^>]*>[\s\S]*?<\/div>/gi, '')
    .replace(/<img[^>]*src="https?:\/\/[^"]*signitic[^"]*"[^>]*\/?>/gi, '')
    .replace(/<table[^>]*>[\s\S]*?signitic[\s\S]*?<\/table>/gi, '')
    .replace(/<a[^>]*href="https?:\/\/app\.signitic\.com[^"]*"[^>]*>[\s\S]*?<\/a>/gi, '')
    .replace(/(<br\s*\/?>[\s]*){3,}/gi, '<br><br>')
    .replace(/<div[^>]*>[\s]*<\/div>/gi, '')
    .trim();
}

// ============================================
// GÉNÉRATION DU MARKDOWN POUR DUST
// ============================================

function htmlToMarkdown(text) {
  if (!text) return '';
  let md = cleanEmailText(text);
  return [
    '# ' + emailSubject,
    '',
    '**De:** ' + senderName + ' <' + senderAddress + '>',
    '**Date:** ' + emailDate,
    '',
    '---',
    '',
    md
  ].join('\n');
}

// ============================================
// GÉNÉRATION DU HTML PROPRE POUR LE FRONT
// ============================================

function generateCleanHtml(html, text) {
  if (html) return cleanEmailHtml(html);
  if (text) {
    let cleaned = cleanEmailText(text);
    return cleaned
      .replace(/&/g, '&amp;')
      .replace(/</g, '&lt;')
      .replace(/>/g, '&gt;')
      .replace(/\n\n/g, '</p><p>')
      .replace(/\n/g, '<br>')
      .replace(/^/, '<p>')
      .replace(/$/, '</p>');
  }
  return '<p>Aucun contenu disponible</p>';
}

